import { useNavigate } from "react-router-dom";
import "./Home.css"; // можно оставить пустым или добавить стили позже

const Home = () => {
  const navigate = useNavigate();

  return (
    <div className="home-container">
      <h1>Ласкаво просимо на платформу подій!</h1>
      <p>Тут можна переглядати події, новини та дізнатись більше про нас.</p>
    </div>
  );
};

export default Home;
